I I tried to implement my own IOSystem/IOStream without aNativeActivity, but I run into some problems and I am not sure if it is related to my code or not. To implement the IOSystem/IOStream I used the current available AndroidJNIIOSystem as well as the information posted in these two blogposts:
[http://shellblade.net/android-assimp.html](http://shellblade.net/android-assimp.html) and (android_fopen, android implementation of FILE)[http://www.50ply.com/blog/2013/01/19/loading-compressed-android-assets-with-file-pointer/](http://www.50ply.com/blog/2013/01/19/loading-compressed-android-assets-with-file-pointer/).
In my application I will end up reading OGRE models, thus at the moment I am testing the code with the Mesh.mesh.xml available in the example folder. I also tried some other files from the examples and my code seems to work occasionally with those.

Implementation of android_fopen as described [http://www.50ply.com/blog/2013/01/19/loading-compressed-android-assets-with-file-pointer/](here):
```
#include <fstream>
#include <android/asset_manager.h>
#include <android/log.h>
 int count =0;
static int android_read(void* cookie, char* buf, int size) {
    __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here android_read, size %d, count %d", size, count++);
    int ret =  AAsset_read((AAsset*)cookie, buf, size);
    if (count < 10){
            __android_log_print(ANDROID_LOG_ERROR, "Assimp", "%s", buf);
    }
    //__android_log_print(ANDROID_LOG_ERROR, "Assimp", "here android_read, buffer return value %d", ret);
    return ret;
}
static int android_write(void* cookie, const char* buf, int size) {
    __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here android_write");
    return 3401;//EACCES;  EACCES	3401	Permission denied. // can't provide write access to the apk
}
static fpos_t android_seek(void* cookie, fpos_t offset, int whence) {
    __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here android_seek");
    return AAsset_seek((AAsset*)cookie, offset, whence);
}
static int android_close(void* cookie) {
    __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here android_close");
    AAsset_close((AAsset*)cookie);
    return 0;
}
FILE* android_fopen(const char* fname, const char* mode, AAssetManager* android_asset_manager) {
    __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here android_fopen");
    if(mode[0] == 'w') return NULL;
    AAsset* asset = AAssetManager_open(android_asset_manager, fname, 0);
    if(!asset) return NULL;
    return funopen(asset, android_read, android_write, android_seek, android_close);
}
```

My implementation of  Assimp::IOStream and Assimp::IOSystem:
```
#include <assimp/IOSystem.hpp>
#include <assimp/IOStream.hpp>
#include <android/asset_manager.h>
#include <android/log.h>
#include <assimp/ai_assert.h>
#include <android_FILE.h> //<- Implementation of the  android_fopen

class MyIOStream final : public Assimp::IOStream
{
public:
    FILE* mFile;
    std::string mFilename;
    mutable size_t cachedSize;
    MyIOStream(){
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here MyIOStream()");
        mFile       = NULL;
        mFilename   ="";
        cachedSize  =SIZE_MAX;
    }
    MyIOStream(FILE* pFile, const std::string &strFilename, size_t size ){
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here MyIOStream(%s,%d)", strFilename.c_str(), size);
        mFile       =pFile;
        mFilename   =strFilename;
        cachedSize  =size;
    }
    // Destructor public to allow simple deletion to close the file.
    ~MyIOStream (){
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here destructor MyIOStream");
        if (mFile) {
            ::fclose(mFile);
            //android_close(mFile);
        }
    }
    size_t Read(void* pvBuffer, size_t pSize, size_t pCount){
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here read MyIOStream %s", mFilename.c_str());
        ai_assert(NULL != pvBuffer && 0 != pSize && 0 != pCount);
        int outcome = fread(pvBuffer, pSize, pCount, mFile);
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here fread outcome %d , size %d , count %d ",outcome, pSize, pCount);
        char* tmp = (char *)pvBuffer;
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "%s",tmp);
        return (mFile ?  outcome : 0);
    }
    size_t Write(const void* pvBuffer, size_t pSize, size_t pCount) override {
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here write MyIOStream");
        throw "MyIOStream::Write() is unsupported";
    }
    aiReturn Seek(size_t pOffset, aiOrigin pOrigin){
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here seek MyIOStream");
        if (!mFile) {
            return AI_FAILURE;
        }
        return (0 == ::fseek(mFile, (long)pOffset,(int)pOrigin) ? AI_SUCCESS : AI_FAILURE);
    }
    size_t Tell() const{
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here tell MyIOStream");
        if (!mFile) {
            return 0;
        }
        return ::ftell(mFile);
    }
    size_t FileSize() const{
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here filesize MyIOStream");
        return cachedSize;
    }
    void Flush() override{
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here flush MyIOStream");
        throw "MyIOStream::Flush() is unsupported";
    }
};

class MyIOSystem final : public Assimp::IOSystem
{
private:
    AAssetManager* mApkAssetManager;
public:
    MyIOSystem(){
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here MyIOSystem()");
    }
    MyIOSystem( AAssetManager* _mApkAssetManager){
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here MyIOSystem() manager");
        mApkAssetManager = _mApkAssetManager;
    }
    ~MyIOSystem(){
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "here ~MyIOSystem()");
    };
    bool Exists( const char* pFile) const {
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "Here IOSystem exist %s", pFile);
        AAsset* asset = AAssetManager_open(mApkAssetManager, pFile, AASSET_MODE_UNKNOWN);
        if (!asset)
        {
            //__android_log_print(ANDROID_LOG_ERROR, "Assimp", "Asset manager can not find: %s", pFile);
            return false;
        }
        AAsset_close(asset);
        return true;
    }
    Assimp::IOStream* Open( const char* strFile, const char* strMode){
        __android_log_print(ANDROID_LOG_ERROR, "Assimp", "Here IOSystem open %s", strFile);
        ai_assert(NULL != strFile);
        ai_assert(NULL != strMode);
        std::vector<char> assetContent;
        off_t assetSize = 0;
        FILE* file = NULL;
        if	(Exists(strFile)){
            AAsset* asset = AAssetManager_open(mApkAssetManager, strFile, AASSET_MODE_UNKNOWN);
            assetSize = AAsset_getLength(asset);
            assetContent.resize(assetSize);
            AAsset_read(asset, &assetContent[0], assetSize);
            AAsset_close(asset);
        }
        file = android_fopen( strFile, strMode, mApkAssetManager);
        if( file == NULL){
            //__android_log_print(ANDROID_LOG_ERROR, "assimp", "here Nule == file");
            return NULL;
        }
        return new MyIOStream(file, strFile, assetSize);
    }
    char getOsSeparator() const{
        return '\\';
    }
    void Close( Assimp::IOStream* pFile){
        __android_log_print(ANDROID_LOG_ERROR, "assimp", "here IOSystem Close file: %s", static_cast<MyIOStream*>(pFile)->mFilename.c_str());
        delete pFile;
    }
    bool ComparePaths (const char* one, const char* second) const{
        __android_log_print(ANDROID_LOG_ERROR, "assimp", "here IOSystem comparepaths");
        ai_assert(NULL != one && NULL != second);
#if (defined _MSC_VER)
        return !(::_stricmp(one,second));
#elif defined( __GNUC__ )
        return !(::strcasecmp(one,second));
#else

        char c1, c2;
        do  {
            c1 = tolower(*one++);
            c2 = tolower(*second++);
        }
        while ( c1 && (c1 == c2) );
        return !(c1 - c2);
#endif
    }
};
```
